<script>
(function(){
  const canvas=document.getElementById('canvas');
  const ctx=canvas.getContext('2d');
  let W,H;
  const particles=[];
  function resize(){W=canvas.width=window.innerWidth;H=canvas.height=window.innerHeight;}
  window.addEventListener('resize',resize);resize();
  const colors=['rgba(57,255,20,','rgba(245,200,66,','rgba(247,168,196,'];
  for(let i=0;i<80;i++){
    particles.push({
      x:Math.random()*window.innerWidth,y:Math.random()*window.innerHeight,
      r:Math.random()*1.8+0.3,vx:(Math.random()-.5)*0.3,vy:-(Math.random()*0.4+0.1),
      a:Math.random(),da:Math.random()*.008+.002,
      color:colors[Math.floor(Math.random()*colors.length)]
    });
  }
  function draw(){
    ctx.clearRect(0,0,W,H);
    particles.forEach(p=>{
      p.x+=p.vx;p.y+=p.vy;p.a+=p.da;
      if(p.a>1||p.a<0)p.da*=-1;
      if(p.y<-10){p.y=H+10;p.x=Math.random()*W;}
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=p.color+p.a+')';ctx.fill();
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

const TEAM1='<?=addslashes($team1Name)?>';
const TEAM2='<?=addslashes($team2Name)?>';
const predLabels={
  team1:'🇫🇷 Victoire '+TEAM1,
  draw:'🤝 Match Nul',
  team2:'🇸🇪 Victoire '+TEAM2
};
const predFR={
  team1:{text:'À mon avis,\nla France va gagner !',sub:'🇫🇷 Allez les Bleues !',color:'#39ff14'},
  draw:{text:'À mon avis,\nce sera un match nul !',sub:'🤝 Partage équitable !',color:'#f5c842'},
  team2:{text:'À mon avis,\nla Suède va gagner !',sub:'🇸🇪 Forza Sverige !',color:'#00bfff'}
};
let selPred=null;

window.addEventListener('load',()=>{
  setTimeout(()=>{
    const s=document.getElementById('splash');
    if(s){s.style.animation='splashFade 0.7s ease forwards';setTimeout(()=>s.remove(),800);}
  },3200);
});

function selectPred(btn){
  document.querySelectorAll('.pred-btn').forEach(b=>b.classList.remove('selected'));
  btn.classList.add('selected');
  selPred=btn.dataset.value;
  document.getElementById('predHidden').value=selPred;
  document.getElementById('predChip').textContent=predLabels[selPred]||'—';
  openModal();
}

function openModal(){
  document.getElementById('modal').classList.add('open');
  document.getElementById('formView').style.display='block';
  document.getElementById('successView').style.display='none';
  document.getElementById('serr').style.display='none';
  document.body.style.overflow='hidden';
  setTimeout(()=>document.getElementById('userName').focus(),120);
}

function closeModal(){
  document.getElementById('modal').classList.remove('open');
  document.body.style.overflow='';
}

document.getElementById('modal').addEventListener('click',e=>{
  if(e.target===document.getElementById('modal'))closeModal();
});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeModal();});

document.getElementById('predForm').addEventListener('submit',async e=>{
  e.preventDefault();
  const name=document.getElementById('userName').value.trim();
  const phone=document.getElementById('userPhone').value.trim();
  let ok=true;
  if(name.length<2){document.getElementById('nameGroup').classList.add('has-err');ok=false;}
  else document.getElementById('nameGroup').classList.remove('has-err');
  if(!/^0?[1-9][0-9]{8}$/.test(phone.replace(/\s/g,''))){document.getElementById('phoneGroup').classList.add('has-err');ok=false;}
  else document.getElementById('phoneGroup').classList.remove('has-err');
  if(!ok)return;
  const btn=document.getElementById('submitBtn');
  btn.disabled=true;btn.textContent='⏳ Envoi en cours…';
  document.getElementById('serr').style.display='none';
  const formData=new FormData(e.target);
  formData.set('phone','+33 '+phone);
  try{
    const res=await fetch('api/submit.php',{method:'POST',body:formData});
    const data=await res.json();
    if(data.success){
      document.getElementById('formView').style.display='none';
      document.getElementById('successView').style.display='block';
      setTimeout(()=>drawShareCard(selPred),200);
    } else {
      const el=document.getElementById('serr');
      el.textContent=data.message||'Erreur. Veuillez réessayer.';
      el.style.display='block';
      btn.disabled=false;btn.textContent='Valider mon Pronostic 🎯';
    }
  }catch(err){
    document.getElementById('serr').textContent='Erreur réseau. Réessayez.';
    document.getElementById('serr').style.display='block';
    btn.disabled=false;btn.textContent='Valider mon Pronostic 🎯';
  }
});

['userName','userPhone'].forEach(id=>{
  document.getElementById(id).addEventListener('input',()=>{
    document.getElementById(id==='userName'?'nameGroup':'phoneGroup').classList.remove('has-err');
  });
});

function drawShareCard(pred){
  const canvas=document.getElementById('shareCanvas');
  if(!canvas)return;
  const ctx=canvas.getContext('2d');
  const W=1080,H=1920;
  canvas.width=W;canvas.height=H;
  const info=predFR[pred]||predFR.team1;

  // Load stadium background
  const img=new Image();
  img.onload=function(){
    // Draw stadium bg
    ctx.drawImage(img,0,0,W,H);

    // Dark overlay gradient
    const ov=ctx.createLinearGradient(0,0,0,H);
    ov.addColorStop(0,'rgba(0,0,0,0.55)');
    ov.addColorStop(0.35,'rgba(0,0,0,0.3)');
    ov.addColorStop(0.6,'rgba(0,0,0,0.75)');
    ov.addColorStop(1,'rgba(0,0,0,0.92)');
    ctx.fillStyle=ov;ctx.fillRect(0,0,W,H);

    // Top colored glow
    const topGlow=ctx.createRadialGradient(W/2,0,0,W/2,0,700);
    topGlow.addColorStop(0,info.color.replace(')',',0.25)').replace('rgb','rgba'));
    topGlow.addColorStop(1,'transparent');
    ctx.fillStyle=topGlow;ctx.fillRect(0,0,W,H);

    // ── TOP BADGE ──
    // UEFA style top bar
    ctx.fillStyle='rgba(255,255,255,0.08)';
    roundRect(ctx,60,80,W-120,90,20);ctx.fill();
    ctx.strokeStyle='rgba(255,255,255,0.15)';ctx.lineWidth=1;
    roundRect(ctx,60,80,W-120,90,20);ctx.stroke();

    ctx.fillStyle='rgba(255,255,255,0.5)';
    ctx.font='bold 32px Arial';ctx.textAlign='center';
    ctx.fillText('⚽  PRONOSTIC DU MATCH  ⚽',W/2,138);

    // ── TEAMS SECTION (middle-top) ──
    const teamY=320;

    // Team 1 circle bg
    const t1g=ctx.createRadialGradient(250,teamY,0,250,teamY,130);
    t1g.addColorStop(0,'rgba(0,30,80,0.8)');t1g.addColorStop(1,'rgba(0,10,40,0.3)');
    ctx.fillStyle=t1g;ctx.beginPath();ctx.arc(250,teamY,120,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle='rgba(255,255,255,0.2)';ctx.lineWidth=2;
    ctx.beginPath();ctx.arc(250,teamY,120,0,Math.PI*2);ctx.stroke();

    // Team 2 circle bg
    const t2g=ctx.createRadialGradient(W-250,teamY,0,W-250,teamY,130);
    t2g.addColorStop(0,'rgba(0,60,30,0.8)');t2g.addColorStop(1,'rgba(0,20,10,0.3)');
    ctx.fillStyle=t2g;ctx.beginPath();ctx.arc(W-250,teamY,120,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle='rgba(255,255,255,0.2)';ctx.lineWidth=2;
    ctx.beginPath();ctx.arc(W-250,teamY,120,0,Math.PI*2);ctx.stroke();

    // Flags
    ctx.font='120px serif';ctx.textAlign='center';
    ctx.fillText('🇫🇷',250,teamY+45);
    ctx.fillText('🇸🇪',W-250,teamY+45);

    // Team names
    ctx.fillStyle='#ffffff';ctx.font='bold 52px Arial';
    ctx.fillText('FRANCE',250,teamY+175);
    ctx.fillText('SUÈDE',W-250,teamY+175);

    // VS orb
    const vsG=ctx.createRadialGradient(W/2,teamY,0,W/2,teamY,80);
    vsG.addColorStop(0,info.color);vsG.addColorStop(1,'rgba(0,0,0,0.5)');
    ctx.fillStyle=vsG;ctx.beginPath();ctx.arc(W/2,teamY,72,0,Math.PI*2);ctx.fill();
    ctx.fillStyle='#000';ctx.font='bold 56px Arial';ctx.textAlign='center';
    ctx.fillText('VS',W/2,teamY+20);

    // ── DIVIDER ──
    const divY=560;
    const divG=ctx.createLinearGradient(0,divY,W,divY);
    divG.addColorStop(0,'transparent');
    divG.addColorStop(0.2,info.color);
    divG.addColorStop(0.8,info.color);
    divG.addColorStop(1,'transparent');
    ctx.strokeStyle=divG;ctx.lineWidth=3;
    ctx.beginPath();ctx.moveTo(60,divY);ctx.lineTo(W-60,divY);ctx.stroke();

    // ── MAIN PREDICTION CARD ──
    const cardY=600,cardH=580;
    // Card background
    const cardG=ctx.createLinearGradient(0,cardY,0,cardY+cardH);
    cardG.addColorStop(0,'rgba(0,0,0,0.6)');cardG.addColorStop(1,'rgba(0,0,0,0.85)');
    ctx.fillStyle=cardG;
    roundRect(ctx,60,cardY,W-120,cardH,32);ctx.fill();
    // Card border with glow
    ctx.strokeStyle=info.color;ctx.lineWidth=3;ctx.shadowColor=info.color;ctx.shadowBlur=20;
    roundRect(ctx,60,cardY,W-120,cardH,32);ctx.stroke();ctx.shadowBlur=0;

    // "À MON AVIS" label
    ctx.fillStyle='rgba(255,255,255,0.4)';
    ctx.font='bold 36px Arial';ctx.textAlign='center';
    ctx.letterSpacing='6px';
    ctx.fillText('À MON AVIS ...',W/2,cardY+70);

    // Main prediction lines
    ctx.shadowColor=info.color;ctx.shadowBlur=30;
    ctx.fillStyle='#ffffff';
    const pLines=info.text.split(String.fromCharCode(10));
    ctx.font='bold 88px Arial';
    pLines.forEach((line,i)=>ctx.fillText(line,W/2,cardY+180+i*105));
    ctx.shadowBlur=0;

    // Sub text with color
    ctx.fillStyle=info.color;
    ctx.font='bold 64px Arial';
    ctx.fillText(info.sub,W/2,cardY+420);

    // Divider inside card
    ctx.strokeStyle='rgba(255,255,255,0.1)';ctx.lineWidth=1;
    ctx.beginPath();ctx.moveTo(120,cardY+470);ctx.lineTo(W-120,cardY+470);ctx.stroke();

    // Hashtag
    ctx.fillStyle='rgba(255,255,255,0.35)';
    ctx.font='36px Arial';
    ctx.fillText('#PronosticFrance #BonoBeauty',W/2,cardY+530);

    // ── BOTTOM PRIZE SECTION ──
    const btmY=1260;
    // Prize card
    const prizeG=ctx.createLinearGradient(0,btmY,0,btmY+200);
    prizeG.addColorStop(0,'rgba(247,168,196,0.15)');prizeG.addColorStop(1,'rgba(232,121,155,0.05)');
    ctx.fillStyle=prizeG;
    roundRect(ctx,60,btmY,W-120,200,24);ctx.fill();
    ctx.strokeStyle='rgba(247,168,196,0.4)';ctx.lineWidth=2;
    roundRect(ctx,60,btmY,W-120,200,24);ctx.stroke();

    ctx.fillStyle='#f7a8c4';ctx.font='bold 42px Arial';ctx.textAlign='center';
    ctx.fillText('💅 Gagnez 50€ SERVICE',W/2,btmY+80);
    ctx.fillStyle='rgba(255,255,255,0.5)';ctx.font='34px Arial';
    ctx.fillText('Faites votre pronostic & tentez votre chance !',W/2,btmY+140);

    // ── SPONSOR LOGOS AREA ──
    const spY=1510;
    ctx.fillStyle='rgba(255,255,255,0.05)';
    roundRect(ctx,60,spY,W-120,120,16);ctx.fill();
    ctx.strokeStyle='rgba(255,255,255,0.1)';ctx.lineWidth=1;
    roundRect(ctx,60,spY,W-120,120,16);ctx.stroke();
    ctx.fillStyle='rgba(255,255,255,0.3)';ctx.font='30px Arial';ctx.textAlign='center';
    ctx.fillText('SERVICE  ·  SERVICE2',W/2,spY+68);

    // ── URL FOOTER ──
    const footG=ctx.createLinearGradient(0,1680,0,1920);
    footG.addColorStop(0,'rgba(0,0,0,0)');footG.addColorStop(1,'rgba(0,0,0,0.8)');
    ctx.fillStyle=footG;ctx.fillRect(0,1680,W,240);

    ctx.fillStyle='rgba(57,255,20,0.9)';ctx.font='bold 44px Arial';ctx.textAlign='center';
    ctx.fillText('football.bonobeauty.fr',W/2,1800);
    ctx.fillStyle='rgba(255,255,255,0.3)';ctx.font='30px Arial';
    ctx.fillText('Participez et tentez de gagner !',W/2,1860);

    // ── CORNER ACCENTS ──
    ctx.strokeStyle=info.color;ctx.lineWidth=6;ctx.shadowColor=info.color;ctx.shadowBlur=15;
    const cs=70;
    // TL
    ctx.beginPath();ctx.moveTo(30+cs,30);ctx.lineTo(30,30);ctx.lineTo(30,30+cs);ctx.stroke();
    // TR
    ctx.beginPath();ctx.moveTo(W-30-cs,30);ctx.lineTo(W-30,30);ctx.lineTo(W-30,30+cs);ctx.stroke();
    // BL
    ctx.beginPath();ctx.moveTo(30,H-30-cs);ctx.lineTo(30,H-30);ctx.lineTo(30+cs,H-30);ctx.stroke();
    // BR
    ctx.beginPath();ctx.moveTo(W-30-cs,H-30);ctx.lineTo(W-30,H-30);ctx.lineTo(W-30,H-30-cs);ctx.stroke();
    ctx.shadowBlur=0;

    // Outer border
    ctx.strokeStyle='rgba(255,255,255,0.12)';ctx.lineWidth=4;ctx.shadowBlur=0;
    ctx.strokeRect(15,15,W-30,H-30);
  };
  img.src='data:image/jpeg;base64,';
}

function roundRect(ctx,x,y,w,h,r){
  ctx.beginPath();
  ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.arcTo(x+w,y,x+w,y+r,r);
  ctx.lineTo(x+w,y+h-r);ctx.arcTo(x+w,y+h,x+w-r,y+h,r);
  ctx.lineTo(x+r,y+h);ctx.arcTo(x,y+h,x,y+h-r,r);
  ctx.lineTo(x,y+r);ctx.arcTo(x,y,x+r,y,r);
  ctx.closePath();
}
</script>
